import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";

const args = parseArgs(process.argv.slice(2));

if (!args.input) {
  fail("Missing --input <path>");
}

if (!args.output) {
  fail("Missing --output <path>");
}

const bundle = JSON.parse(readFileSync(resolve(args.input), "utf8"));
const now = new Date().toISOString();
const datasetStatus = datasetStatusFor(bundle);
const statements = [
  "-- Generated by legal-datavalidation/scripts/export-d1-read-models.mjs",
  "-- Do not edit generated development data by hand.",
  "BEGIN TRANSACTION;",
  "DELETE FROM dataset_status;",
  "DELETE FROM legal_item_overviews;",
  [
    "INSERT INTO dataset_status (id, value_json, updated_at)",
    `VALUES ('current', ${sqlString(JSON.stringify(datasetStatus))}, ${sqlString(now)});`
  ].join(" ")
];

for (const overview of bundle.readModels.legalItemOverviews) {
  statements.push(
    [
      "INSERT INTO legal_item_overviews",
      "(id, title, type, status, summary_plain_language, overview_json, updated_at)",
      "VALUES",
      `(${sqlString(overview.id)}, ${sqlString(overview.title)}, ${sqlString(overview.type)}, ${sqlString(overview.status)}, ${sqlString(overview.summaryPlainLanguage)}, ${sqlString(JSON.stringify(overview))}, ${sqlString(now)});`
    ].join(" ")
  );
}

statements.push("COMMIT;");

mkdirSync(dirname(resolve(args.output)), { recursive: true });
writeFileSync(resolve(args.output), `${statements.join("\n")}\n`, "utf8");

console.log(`Wrote D1 read model SQL: ${args.output}`);
console.log(`Legal item overviews: ${bundle.readModels.legalItemOverviews.length}`);

function datasetStatusFor(bundle) {
  const dataset = bundle.dataset ?? {
    mode: "HUMAN_REVIEWED",
    generatedAt: bundle.approvedAt,
    disposable: false
  };

  return {
    ...dataset,
    approvedAt: bundle.approvedAt,
    approvedBy: bundle.approvedBy,
    counts: {
      legalItems: bundle.legalItems.length,
      provisions: bundle.provisions.length,
      citations: bundle.citations.length,
      relationships: bundle.relationships.length,
      rules: bundle.rules.length,
      concepts: bundle.concepts.length,
      snapshots: bundle.snapshots.length
    },
    validationSummary: bundle.validationSummary
  };
}

function parseArgs(argv) {
  const parsed = {};

  for (let index = 0; index < argv.length; index += 1) {
    const key = argv[index];
    const value = argv[index + 1];

    if (key.startsWith("--")) {
      if (!value || value.startsWith("--")) {
        fail(`Missing value for ${key}`);
      }

      parsed[key.slice(2)] = value;
      index += 1;
    }
  }

  return parsed;
}

function sqlString(value) {
  if (value === undefined || value === null) {
    return "NULL";
  }

  return `'${String(value).replaceAll("'", "''")}'`;
}

function fail(message) {
  console.error(`D1 export failed: ${message}`);
  process.exit(1);
}

